The following Python function attempts to convert second-person archaic English to modern equivalents and strip third-person archaic verbal inflections:

import re
def modernize(text):
    subs = {"thou":"you","thee":"you","thy":"your","thine":"your"}
    for k,v in subs.items():
        text = re.sub(r'\b'+k+r'\b', v, text, flags=re.IGNORECASE)
    text = re.sub(r'\b(\w+)eth\b', lambda m: m.group(1)+'s', text, flags=re.IGNORECASE)
    text = re.sub(r'\b(\w+)est\b', lambda m: m.group(1), text, flags=re.IGNORECASE)
    return text

